{
  "title": "Introduction to AWS for Beginners",
  "description": "This course provides a foundational understanding of Amazon Web Services (AWS), designed specifically for beginners. Participants will learn about key AWS services, best practices, and how to leverage the cloud for various applications.",
  "modules": [
    {
      "id": "module-1",
      "title": "Getting Started with AWS",
      "description": "An introduction to AWS, including account setup, the AWS Management Console, and an overview of core services."
    },
    {
      "id": "module-2",
      "title": "Understanding AWS Core Services",
      "description": "Explore essential AWS services such as EC2, S3, and RDS, and understand their use cases and functionalities."
    },
    {
      "id": "module-3",
      "title": "AWS Security and Best Practices",
      "description": "Learn about AWS security features, identity and access management (IAM), and best practices for securing your AWS environment."
    },
    {
      "id": "module-4",
      "title": "Deploying Applications on AWS",
      "description": "Gain hands-on experience in deploying a simple application on AWS, integrating services, and monitoring performance."
    }
  ]
}
